mapper.insert:
INSERT INTO room_participants (
    user_uuid, room_no, camera_status, mic_status
) VALUES (
    #{userUuid}, #{roomNo}, #{cameraStatus}, #{micStatus}
)

mapper.select:
SELECT *
FROM room_participants
WHERE room_no = #{roomNo}
    AND user_uuid=#{userUuid}

SELECT *
FROM room_participants
WHERE room_no = #{roomNo}
  AND user_uuid = #{userUuid}

SELECT EXISTS (
    SELECT 1
    FROM room_participants
    WHERE room_no = #{roomNo}
      AND user_uuid = #{userUuid}
      AND active = TRUE
)

SELECT EXISTS (
    SELECT 1
    FROM room_participants
    WHERE user_uuid = #{userUuid}
      AND room_no != #{roomNo}
      AND active = TRUE
)

mapper.update:
UPDATE room_participants
SET
    study_seconds = study_seconds + #{seconds},
    updated_at = NOW()
WHERE room_no = #{roomNo}
  AND user_uuid = #{userUuid}
